export type HeaderItem = Readonly<{
  label: string;
  path: string;
  external?: boolean;
}>;

export const SITE_CONFIG = {
  defaultTheme: "light" as "system" | "light" | "dark",
  header: {
    title: "Reads",
    subtitle: "My thoughts, in writing",
    homeLabel: "Home",
    composeLabel: "Compose",
    items: [] as readonly HeaderItem[],
  },
  footer: {
    textTemplate: "{count} article(s) · Designed and developed by [me](https://swetanksubham.com)",
  },
  home: {
    heroTitle: "Insights, ideas, and practical engineering notes",
    heroSubtitle: "A web-first publication with featured stories, latest updates, and weekly highlights.",
    latestTitle: "Latest Articles",
    featuredCount: 1,
    latestCount: 6,
  },
} as const;

export type FooterSegment = Readonly<
  | { readonly kind: "text"; readonly value: string }
  | { readonly kind: "link"; readonly label: string; readonly url: string }
>;

export const parseFooterTemplate = (articleCount: number): ReadonlyArray<FooterSegment> => {
  const text = SITE_CONFIG.footer.textTemplate.replace("{count}", String(articleCount));
  const segments: FooterSegment[] = [];
  const linkPattern = /\[([^\]]+)\]\(([^)]+)\)/g;
  let lastIndex = 0;
  let match: RegExpExecArray | undefined;
  while ((match = linkPattern.exec(text) ?? undefined) !== undefined) {
    if (match.index > lastIndex) {
      segments.push({ kind: "text", value: text.slice(lastIndex, match.index) });
    }
    segments.push({ kind: "link", label: match[1] ?? "", url: match[2] ?? "" });
    lastIndex = match.index + match[0].length;
  }
  if (lastIndex < text.length) {
    segments.push({ kind: "text", value: text.slice(lastIndex) });
  }
  return segments;
};