import { preProcessColumns } from "./columns";
import { preProcessComplexTables } from "./complexTables";
import { preProcessIcons } from "./icons";
import { preProcessSections } from "./sections";

const FENCE_RE = /^(`{3,}|~{3,})[^\n]*\n[\s\S]*?^\1\s*$/gm;

const FENCE_OPEN_RE = /^(`{3,}|~{3,})/;
const HEADING_RE = /^(#{1,6}\s+)/;
const LIST_RE = /^(\s*(?:[-*+]|\d+[.)]) )/;
const QUOTE_RE = /^(>\s*)/;
const HR_RE = /^[-*_]{3,}\s*$/;

const insertMarker = (line: string, lineNum: number): string => {
  const marker = `<span data-source-line="${lineNum}"></span>`;

  const heading = HEADING_RE.exec(line);
  if (heading?.[1]) return heading[1] + marker + line.slice(heading[1].length);

  const list = LIST_RE.exec(line);
  if (list?.[1]) return list[1] + marker + line.slice(list[1].length);

  const quote = QUOTE_RE.exec(line);
  if (quote?.[1]) return quote[1] + marker + line.slice(quote[1].length);

  return marker + line;
};

const isSkippedLine = (trimmed: string): boolean =>
  trimmed === "" || trimmed.startsWith(":::") || trimmed === "+++" || trimmed.startsWith("|") || HR_RE.test(trimmed);

const injectLineMarkers = (md: string): string => {
  const lines = md.split("\n");
  let inFence = false;
  let fenceStr = "";
  let prevWasFenceClose = false;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i] ?? "";
    const trimmed = line.trim();

    if (inFence) {
      if (trimmed.startsWith(fenceStr) && trimmed.slice(fenceStr.length).trim() === "") {
        inFence = false;
        fenceStr = "";
        prevWasFenceClose = true;
      }
      continue;
    }

    const openMatch = FENCE_OPEN_RE.exec(trimmed);
    if (openMatch?.[1]) {
      inFence = true;
      fenceStr = openMatch[1];
      prevWasFenceClose = false;
      continue;
    }

    if (isSkippedLine(trimmed)) {
      prevWasFenceClose = false;
      continue;
    }

    const prev = i > 0 ? (lines[i - 1]?.trim() ?? "") : "";
    const isBlockStart = i === 0 || prev === "" || prev.startsWith(":::") || prev === "+++" || prevWasFenceClose;
    prevWasFenceClose = false;

    if (isBlockStart) {
      lines[i] = insertMarker(line, i + 1);
    }
  }

  return lines.join("\n");
};

export const preProcess = (md: string): string => {
  const withMarkers = injectLineMarkers(md);

  const codeBlocks: string[] = [];
  const masked = withMarkers.replaceAll(FENCE_RE, (match) => {
    codeBlocks.push(match);
    return `\u{FFFE}CB${codeBlocks.length - 1}\u{FFFE}`;
  });

  const processed = preProcessIcons(preProcessComplexTables(preProcessColumns(preProcessSections(masked))));

  return processed.replaceAll(/\u{FFFE}CB(\d+)\u{FFFE}/gu, (_m, i: string) => codeBlocks[Number.parseInt(i, 10)] ?? "");
};
