export const toTitle = (value: string): string => {
  return value
    .replaceAll(/[-_]+/g, " ")
    .split(" ")
    .filter((part) => part.length > 0)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
};

export const toSummary = (markdownBody: string): string => {
  const text = markdownBody
    .replaceAll(/```[\s\S]*?```/g, "")
    .replaceAll(/`([^`]+)`/g, "$1")
    .replaceAll(/\*\*([^*]+)\*\*/g, "$1")
    .replaceAll(/\*([^*]+)\*/g, "$1")
    .replaceAll(/#+\s*/g, "")
    .replaceAll(/\[([^\]]+)\]\([^)]+\)/g, "$1")
    .replaceAll(/<[^>]*>/g, "")
    .replaceAll(/\s+/g, " ")
    .trim();

  if (!text) {
    return "Open this article to read the full content.";
  }

  return text.length > 180 ? `${text.slice(0, 177)}...` : text;
};

export const isExcludedContentPath = (relativePath: string): boolean => {
  const parts = relativePath.split("/");
  return parts.some((part) => part.startsWith("."));
};

export const isUnlistedContentPath = (relativePath: string): boolean => {
  const parts = relativePath.split("/");
  return parts.some((part) => part.startsWith("_"));
};
