import { STATIC_LANGS } from "../constants";
import type { VizCacheMap, VizCleanupMap } from "../types";

type MarkedLike = Readonly<{ parse: (input: string) => string }>;

const toCssValue = (raw: string | undefined): string | undefined => {
  if (!raw) return undefined;
  return /^\d+(\.\d+)?$/.test(raw) ? `${raw}px` : raw;
};

const applyAlignment = (target: HTMLElement, vizEl: HTMLElement | null, vizWidth: string): void => {
  target.style.width = vizWidth;
  const align = vizEl?.dataset.vizAlign || "center";
  if (align === "center") target.style.margin = "0 auto";
  else if (align === "right") target.style.marginLeft = "auto";
};

const decodeBlockCode = (encoded: string): string => {
  const bytes = Uint8Array.from(atob(encoded), (c) => c.codePointAt(0) ?? 0);
  return new TextDecoder().decode(bytes);
};

const fixMermaidDarkText = (svg: SVGSVGElement, isDarkMode: boolean): void => {
  if (!isDarkMode) return;

  // Directly rewrite fill values inside mermaid's own generated <style> block
  const styleEl = svg.querySelector("style");
  if (styleEl?.textContent) {
    // Replace light fill on taskText/doneText classes with dark fill for bar contrast
    styleEl.textContent = styleEl.textContent.replaceAll(
      /(\.(taskText|doneText)\d*\s*\{[^}]*fill:\s*)#[0-9a-fA-F]{3,8}/g,
      "$1#1a1a1a",
    );
  }
};

const initEcharts = (
  target: HTMLElement,
  code: string,
  isDark: boolean | undefined,
): Array<() => void> => {
  const echartsTheme = isDark ? "dark" : undefined;
  const chart = globalThis.echarts!.init(target, echartsTheme, { renderer: "canvas" });
  if (isDark) chart.setOption({ backgroundColor: "transparent" });
  chart.setOption(new Function(`return (${code})`)());
  const onResize = () => chart.resize();
  globalThis.addEventListener("resize", onResize);
  return [() => { globalThis.removeEventListener("resize", onResize); chart.dispose(); }];
};

const renderVizBlock = (
  lang: string,
  target: HTMLElement,
  code: string,
  codeHash: string,
  vizCache: VizCacheMap,
  isDark: boolean | undefined,
): Array<() => void> => {
  const vizEl = target.closest<HTMLElement>(".web-viz");
  const vizHeight = toCssValue(vizEl?.dataset.vizHeight);
  const vizWidth = toCssValue(vizEl?.dataset.vizWidth);
  const vizPadding = toCssValue(vizEl?.dataset.vizPadding);

  if (vizWidth) applyAlignment(target, vizEl, vizWidth);
  if (vizHeight && lang !== "mermaid") target.style.height = vizHeight;
  if (vizPadding) target.style.padding = vizPadding;

  if (lang === "echarts" && globalThis.echarts) {
    target.style.display = "block";
    target.style.position = "relative";
    const cleanupFns = initEcharts(target, code, isDark);
    setTimeout(() => { vizCache.set(codeHash, { lang, html: target.innerHTML }); }, 200);
    return cleanupFns;
  }

  if (lang === "d3" && globalThis.d3) {
    target.style.display = "block";
    new Function("container", "d3", code)(target, globalThis.d3);
    setTimeout(() => { vizCache.set(codeHash, { lang, html: target.innerHTML }); }, 800);
    return [() => { target.innerHTML = ""; }];
  }

  if (lang === "threejs" && globalThis.THREE) {
    target.style.display = "block";
    const cleanup = new Function("container", "THREE", code)(target, globalThis.THREE);
    return [() => {
      if (typeof cleanup === "function") cleanup();
      target.innerHTML = "";
    }];
  }

  /* mermaid is handled in batch by executeVisualizations — skip here */

  if (lang === "webgl") {
    target.style.display = "block";
    const cleanup = new Function("container", code)(target);
    return [() => {
      if (typeof cleanup === "function") cleanup();
      target.innerHTML = "";
    }];
  }

  target.textContent = `Waiting for ${lang}…`;
  return [];
};

type PendingMermaid = Readonly<{
  readonly target: HTMLElement;
  readonly nodeId: string;
  readonly codeHash: string;
  readonly vizWidth: string | undefined;
  readonly vizHeight: string | undefined;
}>;

const applyCachedViz = (
  target: HTMLElement,
  lang: string,
  encoded: string,
  html: string,
  vizWidth: string | undefined,
  vizHeight: string | undefined,
  vizPadding: string | undefined,
): void => {
  target.innerHTML = html;
  if (vizWidth) applyAlignment(target, target.closest<HTMLElement>(".web-viz"), vizWidth);
  if (vizPadding) target.style.padding = vizPadding;
  if (lang === "mermaid") {
    target.style.height = "auto";
    target.style.minHeight = "0";
    target.style.display = "block";
  } else if (vizHeight) {
    target.style.height = vizHeight;
  }
};

const cleanupPrevious = (vizCleanups: VizCleanupMap, codeHash: string): void => {
  const previous = vizCleanups.get(codeHash);
  if (previous) {
    previous.forEach((fn) => { try { fn(); } catch { /* ignore */ } });
    vizCleanups.delete(codeHash);
  }
};

const renderFreshViz = (
  lang: string,
  target: HTMLElement,
  encoded: string,
  codeHash: string,
  vizWidth: string | undefined,
  vizHeight: string | undefined,
  ctx: Readonly<{ vizCache: VizCacheMap; vizCleanups: VizCleanupMap; newCleanups: VizCleanupMap; pendingMermaid: PendingMermaid[]; isDark: boolean | undefined }>,
): void => {
  let code = "";
  try {
    code = decodeBlockCode(encoded);
  } catch {
    target.textContent = "Decode error";
    return;
  }

  target.textContent = "";
  cleanupPrevious(ctx.vizCleanups, codeHash);

  if (lang === "mermaid" && globalThis.mermaid) {
    const nodeId = `mermaid-${codeHash}`;
    target.innerHTML = `<div class="mermaid" id="${nodeId}" style="width:100%">${code}</div>`;
    target.style.display = "block";
    ctx.pendingMermaid.push({ target, nodeId, codeHash, vizWidth, vizHeight });
    ctx.newCleanups.set(codeHash, [() => { target.innerHTML = ""; }]);
    return;
  }

  try {
    ctx.newCleanups.set(codeHash, renderVizBlock(lang, target, code, codeHash, ctx.vizCache, ctx.isDark));
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    target.innerHTML = `<div style="color:#e53e3e;padding:16px;font-family:'JetBrains Mono',monospace;font-size:0.82em;white-space:pre-wrap;">Error: ${message}</div>`;
  }
};

const processVizBlock = (
  block: HTMLElement,
  vizCache: VizCacheMap,
  vizCleanups: VizCleanupMap,
  newCleanups: VizCleanupMap,
  pendingMermaid: PendingMermaid[],
  isDark: boolean | undefined,
): void => {
  const lang = block.dataset.vizLang;
  const codeHash = block.dataset.vizHash;
  const encoded = block.dataset.vizCode;

  if (!lang || !codeHash || !encoded) {
    return;
  }

  const target = document.getElementById(`viz-${codeHash}`);
  if (!target) {
    return;
  }

  const vizWidth = toCssValue(block.dataset.vizWidth);
  const vizHeight = toCssValue(block.dataset.vizHeight);
  const vizPadding = toCssValue(block.dataset.vizPadding);

  const cached = vizCache.get(codeHash);
  if (cached && STATIC_LANGS.has(lang)) {
    applyCachedViz(target, lang, encoded, cached.html, vizWidth, vizHeight, vizPadding);
    if (lang === "echarts" && globalThis.echarts) {
      try {
        target.innerHTML = "";
        newCleanups.set(codeHash, initEcharts(target, decodeBlockCode(encoded), isDark));
      } catch {
        target.textContent = "ECharts re-init failed";
      }
    }
    return;
  }

  renderFreshViz(lang, target, encoded, codeHash, vizWidth, vizHeight, { vizCache, vizCleanups, newCleanups, pendingMermaid, isDark });
};

export const executeVisualizations = (
  el: HTMLElement | null,
  markedLib: MarkedLike,
  vizCache: VizCacheMap,
  vizCleanups: VizCleanupMap,
  isDark?: boolean,
): void => {
  if (!el) {
    return;
  }

  const newCleanups: VizCleanupMap = new Map();

  el.querySelectorAll<HTMLElement>(".expandable-row").forEach((row) => {
    if (row.dataset.bound) {
      return;
    }

    row.dataset.bound = "true";
    row.addEventListener("click", () => {
      const detailId = row.dataset.detail;
      if (!detailId) {
        return;
      }

      const detail = document.getElementById(detailId);
      if (!detail) {
        return;
      }

      const inner = detail.querySelector<HTMLElement>(".detail-inner");
      if (!inner) {
        return;
      }

      const isOpen = inner.style.maxHeight !== "0px" && inner.style.maxHeight !== "";

      if (isOpen) {
        inner.style.maxHeight = "0px";
        inner.style.padding = "0 20px";
      } else {
        inner.style.maxHeight = `${inner.scrollHeight + 40}px`;
        inner.style.padding = "14px 20px";
      }

      const chevron = row.querySelector<HTMLElement>(".expand-chevron");
      if (chevron) {
        chevron.style.transform = isOpen ? "" : "rotate(90deg)";
      }
    });
  });

  el.querySelectorAll<HTMLElement>(".detail-web").forEach((detailNode) => {
    if (detailNode.dataset.parsed) {
      return;
    }

    detailNode.dataset.parsed = "true";
    try {
      detailNode.innerHTML = markedLib.parse(detailNode.textContent ?? "");
    } catch {
      // keep existing text on parse failure
    }
  });

  const pendingMermaid: PendingMermaid[] = [];

  el.querySelectorAll<HTMLElement>(".web-viz").forEach((block) => {
    processVizBlock(block, vizCache, vizCleanups, newCleanups, pendingMermaid, isDark);
  });

  if (pendingMermaid.length > 0 && globalThis.mermaid) {
    const nodes = pendingMermaid
      .map((p) => document.getElementById(p.nodeId))
      .filter((n): n is HTMLElement => n !== null);

    globalThis.mermaid
      .run({ nodes })
      .then(() => {
        for (const { target, nodeId, codeHash, vizWidth, vizHeight } of pendingMermaid) {
          const wrapper = document.getElementById(nodeId);
          if (wrapper) {
            wrapper.style.maxWidth = "100%";
            wrapper.style.width = "100%";
          }
          const svg = target.querySelector("svg");
          if (svg) {
            const origW = svg.getAttribute("width");
            const origH = svg.getAttribute("height");
            if (!svg.getAttribute("viewBox") && origW && origH) {
              svg.setAttribute("viewBox", `0 0 ${Number.parseFloat(origW)} ${Number.parseFloat(origH)}`);
            }
            svg.removeAttribute("style");
            svg.style.maxWidth = "100%";
            svg.style.height = vizHeight ?? "auto";
            svg.style.display = "block";
            svg.style.margin = "0 auto";
            if (vizWidth) {
              svg.removeAttribute("width");
              svg.style.width = "100%";
            }
            fixMermaidDarkText(svg, !!isDark);
          }
          target.style.height = "auto";
          target.style.minHeight = "0";
          target.style.display = "block";
          if (vizWidth) applyAlignment(target, target.closest<HTMLElement>(".web-viz"), vizWidth);
          vizCache.set(codeHash, { lang: "mermaid", html: target.innerHTML });
        }
      })
      .catch(() => undefined);
  }

  for (const [key, value] of newCleanups) {
    vizCleanups.set(key, value);
  }
};
