export const themeToCssVars = (theme: Theme): Readonly<Record<string, string>> => ({
  "--bg": theme.bg,
  "--editor-bg": theme.editorBg,
  "--preview-bg": theme.previewBg,
  "--text": theme.text,
  "--text-muted": theme.textMuted,
  "--border": theme.border,
  "--accent": theme.accent,
  "--accent-soft": theme.accentSoft,
  "--code-bg": theme.codeBg,
  "--code-text": theme.codeText,
  "--blockquote-border": theme.blockquoteBorder,
  "--blockquote-bg": theme.blockquoteBg,
  "--table-stripe": theme.tableStripeBg,
  "--shadow": theme.shadow,
  "--header-bg": theme.headerBg,
  ...(theme.key === "dark"
    ? {
        "--prism-comment": "#6a9955",
        "--prism-punctuation": "#808080",
        "--prism-tag": "#e06c75",
        "--prism-number": "#b5cea8",
        "--prism-string": "#ce9178",
        "--prism-operator": "#d4d4d4",
        "--prism-keyword": "#569cd6",
        "--prism-function": "#dcdcaa",
        "--prism-variable": "#d7ba7d",
      }
    : {
        "--prism-comment": "#6a737d",
        "--prism-punctuation": "#6f6f6f",
        "--prism-tag": "#d73a49",
        "--prism-number": "#005cc5",
        "--prism-string": "#22863a",
        "--prism-operator": "#6f42c1",
        "--prism-keyword": "#d73a49",
        "--prism-function": "#6f42c1",
        "--prism-variable": "#e36209",
      }),
});
