const parseWithMarked = (input: string): string => {
  const parsed = marked.parse(input);
  return typeof parsed === "string" ? parsed : "";
};

type ViewMode = "editor" | "split" | "preview";
type ThemeMode = "system" | "light" | "dark";
type AppRoute = Readonly<{ kind: "home" } | { kind: "compose"; articleId?: string } | { kind: "article"; articleId: string } | { kind: "not-found" }>;

const THEME_STORAGE_KEY = "blogger-theme-mode";
const COMPOSE_WEB_STORAGE_KEY = "blogger-compose-web";
