const MOBILE_BREAKPOINT = 768;
const COMPACT_BREAKPOINT = 1024;

const useIsMobile = (): boolean => {
  const [isMobile, setIsMobile] = useState<boolean>(() => globalThis.innerWidth < MOBILE_BREAKPOINT);
  useEffect(() => {
    const mql = globalThis.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`);
    const handler = (e: MediaQueryListEvent): void => setIsMobile(e.matches);
    setIsMobile(mql.matches);
    mql.addEventListener("change", handler);
    return () => mql.removeEventListener("change", handler);
  }, []);
  return isMobile;
};

const useIsCompact = (): boolean => {
  const [isCompact, setIsCompact] = useState<boolean>(() => globalThis.innerWidth < COMPACT_BREAKPOINT);
  useEffect(() => {
    const mql = globalThis.matchMedia(`(max-width: ${COMPACT_BREAKPOINT - 1}px)`);
    const handler = (e: MediaQueryListEvent): void => setIsCompact(e.matches);
    setIsCompact(mql.matches);
    mql.addEventListener("change", handler);
    return () => mql.removeEventListener("change", handler);
  }, []);
  return isCompact;
};

const readStoredTheme = (): ThemeMode => {
  const stored = localStorage.getItem(THEME_STORAGE_KEY);
  if (stored === "light" || stored === "dark" || stored === "system") return stored;
  return SITE_CONFIG.defaultTheme;
};

const resolveIsDark = (mode: ThemeMode): boolean => {
  if (mode === "light") return false;
  if (mode === "dark") return true;
  return globalThis.matchMedia("(prefers-color-scheme: dark)").matches;
};

const LIB_BADGES = ["marked", "echarts", "d3", "three.js", "mermaid", "webgl", "fa", "devicon"] as const;

const toTitle = (value: string): string => {
  return value
    .replaceAll(/[-_]+/g, " ")
    .split(" ")
    .filter((part) => part.length > 0)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
};

const normalizePath = (value: string): string => {
  if (!value) {
    return "/";
  }

  const normalized = value.endsWith("/") && value.length > 1 ? value.replaceAll(/\/+$/g, "") : value;
  return normalized || "/";
};

const stripSitePrefix = (path: string): string => {
  const normalized = normalizePath(path);
  if (normalized === "/read" || normalized === "/reads") {
    return "/";
  }
  if (normalized.startsWith("/read/")) {
    return normalized.slice("/read".length) || "/";
  }
  if (normalized.startsWith("/reads/")) {
    return normalized.slice("/reads".length) || "/";
  }
  return normalized;
};

const toReadPath = (path: string): string => {
  return path;
};

const normalizeAnchorId = (value: string): string => {
  return value
    .toLowerCase()
    .replaceAll(/[^\w]+/g, "-")
    .replaceAll(/-+/g, "-")
    .replaceAll(/(^-|-$)/g, "");
};

const normalizeManifest = (raw: Record<string, unknown>): ContentManifest => {
  const articles = (raw.articles as Record<string, unknown>[]).map((a): ContentArticle => ({
    id: a.id as string,
    title: a.title as string,
    menuTitle: (a.menuTitle as string) ?? "",
    description: a.description as string,
    date: a.date as string,
    author: a.author as string,
    category: a.category as string,
    tags: (a.tags as readonly string[]) ?? [],
    cover: (a.cover as string) ?? "",
    featured: (a.featured as boolean) ?? false,
    route: a.route as string,
    categoryPath: (a.categoryPath as string[]) ?? [],
  }));
  return {
    generatedAt: raw.generatedAt as string,
    articles,
    categories: raw.categories as readonly ContentCategory[],
    rootArticles: raw.rootArticles as readonly string[],
  };
};

let contentManifestPromise: Promise<ContentManifest> | null = null;

const fetchContentManifest = async (): Promise<ContentManifest> => {
  if (contentManifestPromise) {
    return contentManifestPromise;
  }

  contentManifestPromise = fetch(`${import.meta.env.BASE_URL}content-manifest.json`, {
    cache: "no-cache",
  })
    .then(async (response) => {
      if (!response.ok) {
        throw new Error(`Failed to load manifest: HTTP ${response.status}`);
      }
      return response.json().then(normalizeManifest);
    })
    .catch((error) => {
      contentManifestPromise = null;
      throw error;
    });

  return contentManifestPromise;
};

const fetchMarkdownContent = async (articleId: string): Promise<string> => {
  const response = await fetch(`${import.meta.env.BASE_URL}content/${encodeURI(articleId)}`);
  if (!response.ok) {
    throw new Error(`Failed to load content: HTTP ${response.status}`);
  }
  return response.text();
};

const findArticleById = (manifest: ContentManifest, id: string): ContentArticle | undefined => {
  return manifest.articles.find((article) => article.id === id);
};

const findInitialArticleId = (manifest: ContentManifest): string => {
  return manifest.articles.find((article) => !isUnlistedContentPath(article.id))?.id ?? "";
};

const countCategoryArticles = (category: ContentCategory): number => {
  return category.articles.length + category.categories.reduce((total, nested) => total + countCategoryArticles(nested), 0);
};

const findCategoryPathToArticle = (categories: readonly ContentCategory[], articleId: string): readonly string[] => {
  const walk = (nodes: readonly ContentCategory[]): readonly string[] | null => {
    for (const node of nodes) {
      if (node.articles.includes(articleId)) {
        return [node.id];
      }

      const nested = walk(node.categories);
      if (nested) {
        return [node.id, ...nested];
      }
    }

    return null;
  };

  return walk(categories) ?? [];
};

const SidebarNavigator = ({
  categories,
  rootArticles,
  articleIndex,
  activeArticleId,
  onNavigateArticle,
}: Readonly<{
  categories: readonly ContentCategory[];
  rootArticles: readonly string[];
  articleIndex: ReadonlyMap<string, ContentArticle>;
  activeArticleId?: string | undefined;
  onNavigateArticle: (id: string) => void;
}>): JSX.Element => {
  const [openCategoryIds, setOpenCategoryIds] = useState<Record<string, boolean>>(() => {
    try {
      const stored = sessionStorage.getItem(SIDEBAR_STATE_KEY);
      return stored ? JSON.parse(stored) as Record<string, boolean> : {};
    } catch {
      return {};
    }
  });

  useEffect(() => {
    sessionStorage.setItem(SIDEBAR_STATE_KEY, JSON.stringify(openCategoryIds));
  }, [openCategoryIds]);

  useEffect(() => {
    const styleId = "sb-nav-css";
    if (!document.getElementById(styleId)) {
      const el = document.createElement("style");
      el.id = styleId;
      el.textContent =
        ".sb-cat-btn{display:flex;align-items:center;gap:8px;width:100%;border:none;cursor:pointer;" +
        "padding:9px 10px;text-align:left;background:transparent;border-radius:7px;" +
        "transition:background 150ms ease}" +
        ".sb-cat-btn:hover{background:var(--sb-hover)}" +
        ".sb-art-btn{display:flex;align-items:center;gap:8px;width:100%;border:none;cursor:pointer;" +
        "padding:7px 10px;text-align:left;font-family:inherit;background:transparent;" +
        "border-radius:6px;border-left:3px solid transparent;" +
        "transition:background 150ms ease,border-color 150ms ease}" +
        ".sb-art-btn:hover{background:var(--sb-hover)}" +
        ".sb-art-btn.sb-active{background:var(--sb-active-bg);border-left-color:var(--sb-accent)}";
      document.head.appendChild(el);
    }
  }, []);

  useEffect(() => {
    if (!activeArticleId) {
      return;
    }

    const activePath = findCategoryPathToArticle(categories, activeArticleId);
    if (activePath.length === 0) {
      return;
    }

    setOpenCategoryIds((previous) => {
      const next = { ...previous };
      activePath.forEach((id) => {
        next[id] = true;
      });
      return next;
    });
  }, [activeArticleId, categories]);

  const toggleOpen = useCallback((categoryId: string) => {
    setOpenCategoryIds((previous) => ({
      ...previous,
      [categoryId]: !previous[categoryId],
    }));
  }, []);

  const renderNode = (category: ContentCategory, depth: number): JSX.Element => {
    const isOpen = openCategoryIds[category.id] ?? false;
    const articleCount = countCategoryArticles(category);

    const leftPad = depth === 0 ? 12 : 8;
    const listPadding = isOpen ? `2px 0 6px ${leftPad}px` : `0 0 0 ${leftPad}px`;

    return (
      <li key={category.id}>
        <button type="button" className="sb-cat-btn" onClick={() => toggleOpen(category.id)} title={category.title}>
          {/* Folder icon */}
          <svg
            width="15"
            height="15"
            viewBox="0 0 24 24"
            fill={isOpen ? "var(--sb-folder-fill)" : "none"}
            stroke={isOpen ? "var(--sb-accent)" : "var(--sb-icon)"}
            strokeWidth="1.8"
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{ flexShrink: 0 }}
          >
            <path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z" />
          </svg>
          {/* Category label */}
          <span
            style={{
              flex: 1,
              fontSize: "0.83rem",
              fontWeight: 600,
              color: "var(--sb-text)",
              overflow: "hidden",
              textOverflow: "ellipsis",
              whiteSpace: "nowrap",
            }}
          >
            {category.title}
          </span>
          {/* Article count badge */}
          {articleCount > 0 && (
            <span
              style={{
                fontSize: "0.68rem",
                color: "#7a7568",
                background: "#e6e1d5",
                borderRadius: 999,
                padding: "1px 7px",
                fontWeight: 600,
                flexShrink: 0,
              }}
            >
              {articleCount}
            </span>
          )}
          {/* Chevron icon */}
          <svg
            width="13"
            height="13"
            viewBox="0 0 24 24"
            fill="none"
            stroke="var(--sb-icon)"
            strokeWidth="2.5"
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{
              flexShrink: 0,
              transform: isOpen ? "rotate(90deg)" : "rotate(0deg)",
              transition: "transform 200ms ease",
            }}
          >
            <polyline points="9 18 15 12 9 6" />
          </svg>
        </button>

        <div
          style={{
            display: "grid",
            gridTemplateRows: isOpen ? "1fr" : "0fr",
            transition: "grid-template-rows 250ms cubic-bezier(0.4, 0, 0.2, 1)",
          }}
        >
          <ul
            style={{
              listStyle: "none",
              margin: 0,
              padding: listPadding,
              display: "grid",
              gap: 1,
              overflow: "hidden",
              minHeight: 0,
              transition: "padding 250ms cubic-bezier(0.4, 0, 0.2, 1)",
            }}
          >
            {category.articles.map((articleId) => {
              const article = articleIndex.get(articleId);
              if (!article) return null;
              const isActive = activeArticleId === articleId;
              const label = article.menuTitle || article.title;
              return (
                <li key={article.id}>
                  <button
                    type="button"
                    className={`sb-art-btn${isActive ? " sb-active" : ""}`}
                    onClick={() => onNavigateArticle(article.id)}
                    title={label}
                    style={{ color: isActive ? "var(--sb-text-active)" : "var(--sb-text-item)", fontWeight: isActive ? 600 : 400 }}
                  >
                    <span
                      style={{
                        width: 6,
                        height: 6,
                        borderRadius: 999,
                        background: isActive ? "var(--sb-accent)" : "var(--sb-dot)",
                        flexShrink: 0,
                      }}
                    />
                    <span
                      style={{
                        fontSize: "0.82rem",
                        lineHeight: 1.4,
                        overflow: "hidden",
                        textOverflow: "ellipsis",
                        whiteSpace: "nowrap",
                      }}
                    >
                      {label}
                    </span>
                  </button>
                </li>
              );
            })}
            {category.categories.map((nested) => renderNode(nested, depth + 1))}
          </ul>
        </div>
      </li>
    );
  };

  return (
    <ul style={{ listStyle: "none", margin: 0, padding: 0, display: "grid", gap: 2 }}>
      {rootArticles.map((articleId) => {
        const article = articleIndex.get(articleId);
        if (!article) return null;
        const isActive = activeArticleId === articleId;
        const label = article.menuTitle || article.title;
        return (
          <li key={article.id}>
            <button
              type="button"
              className={`sb-art-btn${isActive ? " sb-active" : ""}`}
              onClick={() => onNavigateArticle(article.id)}
              title={label}
              style={{ color: isActive ? "var(--sb-text-active)" : "var(--sb-text-item)", fontWeight: isActive ? 600 : 400 }}
            >
              <span
                style={{
                  width: 6,
                  height: 6,
                  borderRadius: 999,
                  background: isActive ? "var(--sb-accent)" : "var(--sb-dot)",
                  flexShrink: 0,
                }}
              />
              <span
                style={{
                  fontSize: "0.82rem",
                  lineHeight: 1.4,
                  overflow: "hidden",
                  textOverflow: "ellipsis",
                  whiteSpace: "nowrap",
                }}
              >
                {label}
              </span>
            </button>
          </li>
        );
      })}
      {categories.map((cat) => renderNode(cat, 0))}
    </ul>
  );
};

const resolveRoute = (pathname: string, manifest: ContentManifest): AppRoute => {
  const relativePath = normalizePath(stripSitePrefix(pathname));
  if (relativePath === "/" || relativePath === "") {
    return { kind: "home" };
  }

  if (relativePath === "/compose") {
    return { kind: "compose" };
  }

  if (relativePath.startsWith("/compose/")) {
    const composeRelativePath = normalizePath(relativePath.slice("/compose".length));
    const composeArticle = manifest.articles.find((item) => {
      const articleRelativePath = normalizePath(stripSitePrefix(item.route));
      return articleRelativePath === composeRelativePath;
    });

    if (composeArticle) {
      return { kind: "compose", articleId: composeArticle.id };
    }

    return { kind: "compose" };
  }

  const article = manifest.articles.find((item) => {
    const articleRelativePath = normalizePath(stripSitePrefix(item.route));
    return articleRelativePath === relativePath;
  });

  if (!article) {
    return { kind: "not-found" };
  }

  return { kind: "article", articleId: article.id };
};

const useRenderedMarkdown = (markdown: string, isDark: boolean): Readonly<{
  libsReady: boolean;
  renderedHtml: string;
  metadata: Metadata | null;
  previewRef: React.MutableRefObject<HTMLDivElement | null>;
}> => {
  const [libsReady, setLibsReady] = useState<boolean>(false);
  const [renderedHtml, setRenderedHtml] = useState<string>("");
  const [metadata, setMetadata] = useState<Metadata | null>(null);

  const previewRef = useRef<HTMLDivElement | null>(null);
  const vizCacheRef = useRef<VizCacheMap>(new Map());
  const vizCleanupsRef = useRef<VizCleanupMap>(new Map());

  useEffect(() => {
    void vizLibsReady.then(() => setLibsReady(true));
  }, []);

  useEffect(() => {
    if (!libsReady) {
      return;
    }

    try {
      resetTableCounter();
      const { metadata: parsedMetadata, body } = parseFrontmatter(markdown);
      setMetadata(parsedMetadata);
      setRenderedHtml(parseWithMarked(preProcess(body)));
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      setRenderedHtml(`<p style="color:red;">Parse error: ${message}</p>`);
    }
  }, [markdown, libsReady]);

  useEffect(() => {
    if (!previewRef.current || !libsReady) {
      return;
    }

    const currentHashes = new Set<string>();
    previewRef.current.querySelectorAll<HTMLElement>(".web-viz").forEach((block) => {
      if (block.dataset.vizHash) {
        currentHashes.add(block.dataset.vizHash);
      }
    });

    for (const [hash, cleanups] of vizCleanupsRef.current) {
      if (!currentHashes.has(hash)) {
        cleanups.forEach((cleanup) => {
          try {
            cleanup();
          } catch {
            // no-op
          }
        });
        vizCleanupsRef.current.delete(hash);
        vizCacheRef.current.delete(hash);
      }
    }

    const timer = globalThis.setTimeout(() => {
      executeVisualizations(previewRef.current, { parse: parseWithMarked }, vizCacheRef.current, vizCleanupsRef.current, isDark);
    }, 80);

    return () => globalThis.clearTimeout(timer);
  }, [renderedHtml, libsReady, isDark]);

  useEffect(() => {
    if (!previewRef.current) {
      return;
    }

    const onClick = (event: MouseEvent) => {
      const target = event.target;
      if (!(target instanceof Element)) {
        return;
      }

      const anchor = target.closest<HTMLAnchorElement>('a[href^="#"]');
      if (!anchor) {
        return;
      }

      const href = anchor.getAttribute("href");
      if (!href || href.length <= 1) {
        return;
      }

      const rawId = decodeURIComponent(href.slice(1));
      const normalizedId = normalizeAnchorId(rawId);
      const container = previewRef.current;
      if (!container) {
        return;
      }

      const section =
        container.querySelector<HTMLElement>(`#${CSS.escape(rawId)}`) ??
        container.querySelector<HTMLElement>(`#${CSS.escape(normalizedId)}`) ??
        Array.from(container.querySelectorAll<HTMLElement>("h1[id], h2[id], h3[id], h4[id], h5[id], h6[id]")).find(
          (heading) => normalizeAnchorId(heading.id) === normalizedId,
        );
      if (!section) {
        return;
      }

      event.preventDefault();
      section.scrollIntoView({ behavior: "smooth", block: "start" });
      globalThis.history.replaceState({}, "", `#${encodeURIComponent(section.id)}`);
    };

    const container = previewRef.current;
    container.addEventListener("click", onClick);
    return () => {
      container.removeEventListener("click", onClick);
    };
  }, [renderedHtml]);

  useEffect(() => {
    if (!previewRef.current) return;
    const container = previewRef.current;

    const markCopied = (btn: HTMLButtonElement): void => {
      btn.classList.add("copied");
      setTimeout(() => btn.classList.remove("copied"), 1500);
    };

    const onCopyClick = (event: MouseEvent): void => {
      const btn = (event.target as Element).closest<HTMLButtonElement>(".code-copy-btn");
      if (!btn) return;
      const encoded = btn.dataset.code;
      if (!encoded) return;
      try {
        const binary = atob(encoded);
        const bytes = Uint8Array.from(binary, (ch) => ch.codePointAt(0)!);
        const text = new TextDecoder().decode(bytes);
        void navigator.clipboard.writeText(text).then(() => markCopied(btn));
      } catch { /* ignore decode errors */ }
    };

    container.addEventListener("click", onCopyClick);

    const scrollHostEl = container.closest<HTMLElement>('[data-region="content"]');
    const scrollTarget: HTMLElement | typeof globalThis = scrollHostEl ?? globalThis;

    const repositionCopyBtns = (): void => {
      const visibleTop = scrollHostEl ? scrollHostEl.getBoundingClientRect().top : 0;
      const wrappers = container.querySelectorAll<HTMLElement>(".code-block-wrapper");
      for (const wrapper of wrappers) {
        const btn = wrapper.querySelector<HTMLButtonElement>(".code-copy-btn");
        if (!btn) continue;
        const rect = wrapper.getBoundingClientRect();
        const defaultTop = 28;
        if (rect.top >= visibleTop) {
          btn.style.top = `${defaultTop}px`;
        } else {
          const offset = visibleTop - rect.top + 10;
          const maxTop = rect.height - 40;
          btn.style.top = `${Math.max(defaultTop, Math.min(offset, maxTop))}px`;
        }
      }
    };
    scrollTarget.addEventListener("scroll", repositionCopyBtns, { passive: true });
    repositionCopyBtns();

    return () => {
      container.removeEventListener("click", onCopyClick);
      scrollTarget.removeEventListener("scroll", repositionCopyBtns);
    };
  }, [renderedHtml]);

  useEffect(() => {
    if (!globalThis.mermaid) return;

    globalThis.mermaid.initialize({
      startOnLoad: false,
      theme: isDark ? "dark" : "neutral",
      securityLevel: "loose",
      maxTextSize: 100_000,
      mindmap: { maxNodeWidth: 300, padding: 16 },
      flowchart: { useMaxWidth: false, padding: 40 },
      sequence: { useMaxWidth: true },
      gantt: { useMaxWidth: true },
      ...(isDark && {
        themeVariables: {
          taskTextColor: "#e0e0e0",
          taskTextDarkColor: "#e0e0e0",
          taskTextOutsideColor: "#e0e0e0",
          sectionBkgColor: "#2a2a2a",
          sectionBkgColor2: "#333333",
          gridColor: "#444444",
          todayLineColor: "#ff6b6b",
        },
      }),
    });

    for (const [hash, cache] of vizCacheRef.current) {
      if (cache.lang === "mermaid" || cache.lang === "echarts") {
        const cleanups = vizCleanupsRef.current.get(hash);
        if (cleanups) {
          cleanups.forEach((cleanup) => { try { cleanup(); } catch { /* no-op */ } });
          vizCleanupsRef.current.delete(hash);
        }
        vizCacheRef.current.delete(hash);
      }
    }
  }, [isDark]);

  useEffect(() => {
    return () => {
      for (const cleanups of vizCleanupsRef.current.values()) {
        cleanups.forEach((cleanup) => {
          try {
            cleanup();
          } catch {
            // no-op
          }
        });
      }
    };
  }, []);

  return { libsReady, renderedHtml, metadata, previewRef };
};

