  isDark ? SHELL_CSS_VARS_DARK : SHELL_CSS_VARS_LIGHT;

const LOADER_REVEAL_DELAY_MS = 150;

const RouteLoader = ({
  isDark,
  label,
}: Readonly<{
  isDark: boolean;
  label: string;
}>): JSX.Element => {
  const [showLoader, setShowLoader] = useState<boolean>(false);

  useEffect(() => {
    setShowLoader(false);
    const timer = globalThis.setTimeout(() => {
      setShowLoader(true);
    }, LOADER_REVEAL_DELAY_MS);

    return () => {
      globalThis.clearTimeout(timer);
    };
  }, [label]);

  const theme: Theme = isDark ? THEME_DARK : THEME_LIGHT;
  const cssVars = themeToCssVars(theme);

  return (
    <div
      style={{
        ...cssVars,
        height: "100%",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        gap: 10,
        color: "var(--text-muted)",
        background: "var(--bg)",
      }}
    >
      {showLoader ? (
        <>
          <span style={{ width: 16, height: 16, border: "2px solid var(--border)", borderTopColor: "var(--accent)", borderRadius: "50%", animation: "spin 0.6s linear infinite" }} />
          <span>{label}</span>
        </>
      ) : null}
    </div>
  );
};

