class ErrorBoundary extends React.Component<
  Readonly<{ isDark: boolean; onGoHome: () => void; children: React.ReactNode }>,
  Readonly<{ hasError: boolean; errorMessage: string }>
> {
  constructor(props: Readonly<{ isDark: boolean; onGoHome: () => void; children: React.ReactNode }>) {
    super(props);
    this.state = { hasError: false, errorMessage: "" };
  }

  static getDerivedStateFromError(error: unknown): { hasError: boolean; errorMessage: string } {
    return { hasError: true, errorMessage: error instanceof Error ? error.message : String(error) };
  }

  override render(): React.ReactNode {
    if (this.state.hasError) {
      return (
        <ErrorPage
          isDark={this.props.isDark}
          title="Something went wrong"
          message={this.state.errorMessage || "An unexpected error occurred while rendering this page."}
          onRetry={() => this.setState({ hasError: false, errorMessage: "" })}
          onGoHome={this.props.onGoHome}
        />
      );
    }
    return this.props.children;
  }
}

const themeIcon = (mode: ThemeMode | "default"): string => {
  if (mode === "dark") return "☾";
  if (mode === "light") return "☀";
  if (mode === "default") return "✦";
  return "◐";
};

const ThemeSelector = ({
  isDark,
  themeMode,
  onSetThemeMode,
}: Readonly<{
  isDark: boolean;
  themeMode: ThemeMode;
  onSetThemeMode: (mode: ThemeMode | "default") => void;
}>): JSX.Element => {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    if (!open) return;
    const handleClick = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        setOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, [open]);

  const dropBg = isDark ? "#1a1a19" : "#fff";
  const dropBorder = isDark ? "#333" : "#e6e5df";
  const dropColor = isDark ? "#e8e8e2" : "#1c1c1a";
  const dropShadow = isDark ? "0 4px 12px rgba(0,0,0,0.4)" : "0 4px 12px rgba(0,0,0,0.1)";

  return (
    <div ref={ref} style={{ position: "relative" }}>
      <button
        type="button"
        onClick={() => setOpen((v) => !v)}
        style={{
          border: "1px solid",
          borderColor: dropBorder,
          background: dropBg,
          borderRadius: 7,
          padding: "6px 8px",
          fontSize: "0.85rem",
          cursor: "pointer",
          color: dropColor,
          display: "inline-flex",
          alignItems: "center",
          gap: 4,
        }}
        title="Theme"
      >
        {themeIcon(themeMode)}
      </button>
      {open && (
        <div
          style={{
            position: "absolute",
            right: 0,
            top: "calc(100% + 6px)",
            background: dropBg,
            border: "1px solid",
            borderColor: dropBorder,
            borderRadius: 8,
            boxShadow: dropShadow,
            padding: 4,
            zIndex: 200,
            minWidth: 120,
            animation: "fadeIn 0.12s ease",
          }}
        >
          {(["default", "system", "light", "dark"] as const).map((mode) => {
            const isActive = mode === "default"
              ? !localStorage.getItem(THEME_STORAGE_KEY)
              : themeMode === mode && Boolean(localStorage.getItem(THEME_STORAGE_KEY));
            let activeBg = "transparent";
            if (isActive) {
              activeBg = isDark ? "#2a2a28" : "#f5f3ee";
            }
            return (
              <button
                key={mode}
                type="button"
                onClick={() => { onSetThemeMode(mode); setOpen(false); }}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 8,
                  width: "100%",
                  padding: "7px 10px",
                  border: "none",
                  borderRadius: 5,
                  background: activeBg,
                  color: dropColor,
                  cursor: "pointer",
                  fontSize: "0.82rem",
                  fontWeight: isActive ? 600 : 400,
                  fontFamily: "inherit",
                  textAlign: "left",
                }}
              >
                <span style={{ width: 16, textAlign: "center" }}>
                  {themeIcon(mode)}
                </span>
                {mode.charAt(0).toUpperCase() + mode.slice(1)}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
};

