const SWIPE_THRESHOLD = 60;
const SWIPE_MAX_VERTICAL = 100;

const useSwipeToClose = (
  ref: React.RefObject<HTMLElement | null>,
  enabled: boolean,
  onClose: () => void,
): void => {
  useEffect(() => {
    if (!enabled) return;
    const el = ref.current;
    if (!el) return;

    let startX = 0;
    let startY = 0;

    const onTouchStart = (e: TouchEvent): void => {
      const touch = e.touches[0];
      if (!touch) return;
      startX = touch.clientX;
      startY = touch.clientY;
    };

    const onTouchEnd = (e: TouchEvent): void => {
      const touch = e.changedTouches[0];
      if (!touch) return;
      const dx = touch.clientX - startX;
      const dy = Math.abs(touch.clientY - startY);
      if (dx < -SWIPE_THRESHOLD && dy < SWIPE_MAX_VERTICAL) onClose();
    };

    el.addEventListener("touchstart", onTouchStart, { passive: true });
    el.addEventListener("touchend", onTouchEnd, { passive: true });
    return () => {
      el.removeEventListener("touchstart", onTouchStart);
      el.removeEventListener("touchend", onTouchEnd);
    };
  }, [ref, enabled, onClose]);
};

const PULL_REFRESH_THRESHOLD = 80;
const PULL_REFRESH_MAX_PULL = 130;

const usePullToRefresh = (
  scrollRef: React.RefObject<HTMLElement | null>,
): Readonly<{ pullDistance: number; refreshing: boolean }> => {
  const [pullDistance, setPullDistance] = useState<number>(0);
  const [refreshing, setRefreshing] = useState<boolean>(false);
  const trackingRef = useRef<boolean>(false);
  const startYRef = useRef<number>(0);
  const distanceRef = useRef<number>(0);

  useEffect(() => {
    const el = scrollRef.current;
    if (!el) return;

    const onTouchStart = (e: TouchEvent): void => {
      if (refreshing) return;
      const touch = e.touches[0];
      if (!touch) return;
      if (el.scrollTop <= 0) {
        trackingRef.current = true;
        startYRef.current = touch.clientY;
      }
    };

    const onTouchMove = (e: TouchEvent): void => {
      if (!trackingRef.current || refreshing) return;
      const touch = e.touches[0];
      if (!touch) return;
      const dy = touch.clientY - startYRef.current;
      if (dy > 0 && el.scrollTop <= 0) {
        const clamped = Math.min(dy * 0.5, PULL_REFRESH_MAX_PULL);
        distanceRef.current = clamped;
        setPullDistance(clamped);
        if (clamped > 10) e.preventDefault();
      } else {
        trackingRef.current = false;
        distanceRef.current = 0;
        setPullDistance(0);
      }
    };

    const onTouchEnd = (): void => {
      if (!trackingRef.current) return;
      trackingRef.current = false;
      if (distanceRef.current >= PULL_REFRESH_THRESHOLD) {
        setRefreshing(true);
        distanceRef.current = PULL_REFRESH_THRESHOLD;
        setPullDistance(PULL_REFRESH_THRESHOLD);
        globalThis.location.reload();
      } else {
        distanceRef.current = 0;
        setPullDistance(0);
      }
    };

    el.addEventListener("touchstart", onTouchStart, { passive: true });
    el.addEventListener("touchmove", onTouchMove, { passive: false });
    el.addEventListener("touchend", onTouchEnd, { passive: true });
    return () => {
      el.removeEventListener("touchstart", onTouchStart);
      el.removeEventListener("touchmove", onTouchMove);
      el.removeEventListener("touchend", onTouchEnd);
    };
  }, [scrollRef, refreshing]);

  return { pullDistance, refreshing };
};

const PullRefreshIndicator = ({
  pullDistance,
  refreshing,
  tracking,
}: Readonly<{
  pullDistance: number;
  refreshing: boolean;
  tracking: boolean;
}>): JSX.Element | null => {
  if (pullDistance <= 0) return null;
  const progress = Math.min(pullDistance / PULL_REFRESH_THRESHOLD, 1);
  return (
    <div
      className="pull-refresh-indicator"
      style={{
        height: pullDistance,
        transition: tracking ? "none" : "height 0.25s ease",
      }}
    >
      <div
        style={{
          opacity: progress,
          transform: refreshing ? undefined : `rotate(${progress * 180}deg)`,
        }}
        className={refreshing ? "pull-refresh-spinner" : undefined}
      >
        <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          {refreshing ? (
            <path d="M21 12a9 9 0 1 1-6.219-8.56" />
          ) : (
            <><polyline points="7 13 12 18 17 13" /><line x1="12" y1="6" x2="12" y2="18" /></>
          )}
        </svg>
      </div>
    </div>
  );
};

