const SharedShell = ({
  manifest,
  currentPath,
  onNavigateHome,
  onNavigateCompose,
  onNavigateTo,
  onNavigateArticle,
  sidebarArticleOverride,
  themeMode,
  onSetThemeMode,
  isDark,
  children,
}: Readonly<{
  manifest: ContentManifest;
  currentPath: string;
  onNavigateHome: () => void;
  onNavigateCompose: () => void;
  onNavigateTo: (path: string) => void;
  onNavigateArticle: (id: string) => void;
  sidebarArticleOverride?: ((id: string) => void) | undefined;
  themeMode: ThemeMode;
  onSetThemeMode: (mode: ThemeMode | "default") => void;
  isDark: boolean;
  children: JSX.Element;
}>): JSX.Element => {
  const normalized = normalizePath(stripSitePrefix(currentPath));
  const isMobile = useIsMobile();
  const isCompact = useIsCompact();
  const headerHeight = isMobile ? 56 : 64;
  const articleMatchPath = normalized.startsWith("/compose/")
    ? normalizePath(normalized.slice("/compose".length))
    : normalized;
  const activeArticleId = manifest.articles.find((article) => normalizePath(stripSitePrefix(article.route)) === articleMatchPath)?.id;
  const [sidebarQuery, setSidebarQuery] = useState<string>("");
  const articleIndex = useMemo(() => new Map(manifest.articles.map((a) => [a.id, a])), [manifest.articles]);
  const [sidebarCollapsed, setSidebarCollapsed] = useState<boolean>(() => {
    if (globalThis.innerWidth < COMPACT_BREAKPOINT) return true;
    const stored = sessionStorage.getItem(SIDEBAR_COLLAPSED_KEY);
    return stored === null ? true : stored === "1";
  });
  const [sidebarUserToggled, setSidebarUserToggled] = useState<boolean>(() => sessionStorage.getItem(SIDEBAR_COLLAPSED_KEY) !== null);
  const [showScrollTop, setShowScrollTop] = useState<boolean>(false);
  const contentScrollRef = useRef<HTMLDivElement | null>(null);
  const { pullDistance, refreshing: pullRefreshing } = usePullToRefresh(contentScrollRef);
  const trackingPull = pullDistance > 0 && !pullRefreshing;

  useEffect(() => {
    if (sidebarUserToggled || isCompact) {
      return;
    }

    const shouldExpandForPage = Boolean(activeArticleId) || normalized === "/compose" || normalized === "/";
    setSidebarCollapsed(!shouldExpandForPage);
  }, [activeArticleId, normalized, sidebarUserToggled, isCompact]);

  useEffect(() => {
    const styleId = "layout-css";
    if (!document.getElementById(styleId)) {
      const el = document.createElement("style");
      el.id = styleId;
      el.textContent =
        ".app-container{width:100%}" +
        "@media(min-width:1920px){.app-container{max-width:1920px;margin:0 auto}}";
      document.head.appendChild(el);
    }
  }, []);

  useEffect(() => {
    const styleId = "scrollbar-theme-css";
    let el = document.getElementById(styleId) as HTMLStyleElement | null;
    if (!el) {
      el = document.createElement("style");
      el.id = styleId;
      document.head.appendChild(el);
    }
    const thumb = isDark ? "rgba(255,255,255,0.15)" : "rgba(0,0,0,0.15)";
    const thumbHover = isDark ? "rgba(255,255,255,0.25)" : "rgba(0,0,0,0.25)";
    el.textContent = `:root{--scrollbar-thumb:${thumb};--scrollbar-thumb-hover:${thumbHover}}`;
  }, [isDark]);

  useEffect(() => {
    contentScrollRef.current?.scrollTo({ top: 0 });
  }, [currentPath]);

  useEffect(() => {
    const scrollHost = contentScrollRef.current;
    if (!scrollHost) {
      return;
    }

    const handleScroll = () => {
      setShowScrollTop(scrollHost.scrollTop > 240);
    };

    handleScroll();
    scrollHost.addEventListener("scroll", handleScroll, { passive: true });
    return () => {
      scrollHost.removeEventListener("scroll", handleScroll);
    };
  }, [currentPath]);

  const sidebarSearchResults = useMemo(() => {
    const query = sidebarQuery.trim().toLowerCase();
    if (!query) {
      return [] as ContentArticle[];
    }

    return manifest.articles.filter((article) => {
      if (isUnlistedContentPath(article.id)) {
        return false;
      }
      const haystack = [
        article.title,
        article.menuTitle,
        article.description,
        article.category,
        article.author,
        ...article.tags,
        ...article.categoryPath,
      ].join(" ").toLowerCase();

      return haystack.includes(query);
    });
  }, [manifest.articles, sidebarQuery]);

  const sidebarNavigate = useCallback((id: string) => {
    onNavigateArticle(id);
    if (isCompact) setSidebarCollapsed(true);
  }, [onNavigateArticle, isCompact]);

  const sidebarOverrideNavigate = useMemo(() => {
    if (!sidebarArticleOverride) return undefined;
    return (id: string) => {
      sidebarArticleOverride(id);
      if (isCompact) setSidebarCollapsed(true);
    };
  }, [sidebarArticleOverride, isCompact]);

  const { shellBg, shellColor, borderColor, headerBg, sidebarBg, sidebarBorder, mutedColor } = getShellColors(isDark);
  const shellCssVars = getShellCssVars(isDark);

  return (
    <div style={{ height: "100dvh", display: "flex", flexDirection: "column", background: shellBg, color: shellColor, overflow: "hidden", ...shellCssVars }}>
      <header
        style={{
          borderBottom: `1px solid ${borderColor}`,
          background: headerBg,
          position: "fixed",
          top: 0,
          left: 0,
          right: 0,
          zIndex: 100,
        }}
      >
        <div className="app-container" style={{ padding: isMobile ? "10px 0" : "14px 0", display: "flex", alignItems: "center" }}>
          {/* Branding — same width as sidebar on desktop */}
          <button type="button" style={{ width: isCompact ? "auto" : 340, flexShrink: 0, display: "flex", alignItems: "center", gap: 10, padding: isMobile ? "0 8px 0 12px" : "0 10px 0 18px", cursor: "pointer", boxSizing: "border-box", border: "none", background: "transparent", color: "inherit", font: "inherit", textAlign: "left" }} onClick={onNavigateHome}>
            <div style={{ width: 28, height: 28, borderRadius: 6, background: "#c24d00", display: "flex", alignItems: "center", justifyContent: "center" }}>
              <svg width="15" height="15" viewBox="0 0 16 16" fill="none">
                <path d="M2 4h3l2 4-2 4H2l2-4-2-4zm7 0h3l2 4-2 4H9l2-4-2-4z" fill="white" fillOpacity="0.95" />
              </svg>
            </div>
            <div>
              <div style={{ fontWeight: 700, fontSize: isMobile ? "0.92rem" : "1.03rem", letterSpacing: "-0.01em" }}>{SITE_CONFIG.header.title}</div>
              {!isMobile && <div style={{ fontSize: "0.78rem", color: mutedColor }}>{SITE_CONFIG.header.subtitle}</div>}
            </div>
          </button>
          {/* Center — toggle + flexible space */}
          <div style={{ flex: 1, display: "flex", alignItems: "center" }}>
            <button
              type="button"
              onClick={() => {
                if (!isCompact) setSidebarUserToggled(true);
                setSidebarCollapsed((v) => {
                  const next = !v;
                  if (!isCompact) sessionStorage.setItem(SIDEBAR_COLLAPSED_KEY, next ? "1" : "0");
                  return next;
                });
              }}
              title={sidebarCollapsed ? "Show sidebar" : "Hide sidebar"}
              style={{
                border: "none",
                background: "transparent",
                borderRadius: 6,
                padding: 6,
                cursor: "pointer",
                color: mutedColor,
                display: "inline-flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            >
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <line x1="3" y1="6" x2="21" y2="6" />
                <line x1="3" y1="12" x2="21" y2="12" />
                <line x1="3" y1="18" x2="21" y2="18" />
              </svg>
            </button>
          </div>
          {/* Actions */}
          <nav style={{ display: "flex", alignItems: "center", gap: 6, flexWrap: "wrap", justifyContent: "flex-end", paddingRight: isMobile ? 10 : 18 }}>
            {SITE_CONFIG.header.items.map((item) => {
              const buttonStyle = {
                border: `1px solid ${borderColor}`,
                background: headerBg,
                borderRadius: 7,
                padding: "6px 10px",
                fontSize: "0.8rem",
                cursor: "pointer",
                textDecoration: "none",
                color: shellColor,
                display: "inline-flex",
                alignItems: "center",
              } as const;

              if (item.external) {
                return (
                  <a
                    key={item.path}
                    href={item.path}
                    target="_blank"
                    rel="noreferrer"
                    style={buttonStyle}
                  >
                    {item.label}
                  </a>
                );
              }

              return (
                <button
                  key={item.path}
                  type="button"
                  onClick={() => onNavigateTo(item.path)}
                  style={buttonStyle}
                >
                  {item.label}
                </button>
              );
            })}
            <ThemeSelector isDark={isDark} themeMode={themeMode} onSetThemeMode={onSetThemeMode} />
          </nav>
        </div>
      </header>

      <div className="app-container" style={{ flex: 1, display: "flex", paddingTop: headerHeight, overflow: "hidden", position: "relative" }}>
        <SidebarPanel
          isMobile={isMobile}
          isCompact={isCompact}
          sidebarCollapsed={sidebarCollapsed}
          onClose={() => setSidebarCollapsed(true)}
          headerHeight={headerHeight}
          sidebarBg={sidebarBg}
          sidebarBorder={sidebarBorder}
          manifest={manifest}
          sidebarQuery={sidebarQuery}
          onSidebarQueryChange={setSidebarQuery}
          searchResults={sidebarSearchResults}
          activeArticleId={activeArticleId}
          articleIndex={articleIndex}
          onNavigate={sidebarNavigate}
          onNavigateTree={sidebarOverrideNavigate ?? sidebarNavigate}
        />
        <div ref={contentScrollRef} data-region="content" style={{ flex: 1, minWidth: 0, display: "flex", flexDirection: "column", overflow: "auto", overscrollBehaviorY: "contain" }}>
          <PullRefreshIndicator pullDistance={pullDistance} refreshing={pullRefreshing} tracking={trackingPull} />
          <div style={{ flex: "1 0 auto", position: "relative" }}>{children}</div>
          <button
            type="button"
            onClick={() => contentScrollRef.current?.scrollTo({ top: 0, behavior: "smooth" })}
            title="Scroll to top"
            aria-label="Scroll to top"
            style={{
              position: "fixed",
              right: 20,
              bottom: 20,
              width: 42,
              height: 42,
              borderRadius: 999,
              border: `1px solid ${borderColor}`,
              background: headerBg,
              color: shellColor,
              display: "inline-flex",
              alignItems: "center",
              justifyContent: "center",
              cursor: showScrollTop ? "pointer" : "default",
              boxShadow: isDark ? "0 6px 18px rgba(0,0,0,0.45)" : "0 6px 18px rgba(0,0,0,0.15)",
              opacity: showScrollTop ? 1 : 0,
              pointerEvents: showScrollTop ? "auto" : "none",
              transition: "opacity 0.2s ease",
              zIndex: 120,
            }}
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="18 15 12 9 6 15" />
            </svg>
          </button>
          <footer style={{ flexShrink: 0, borderTop: `1px solid ${borderColor}`, background: headerBg }}>
            <div className="app-container" style={{ padding: "10px 18px", fontSize: "0.78rem", color: mutedColor, textAlign: "center" }}>
              {parseFooterTemplate(manifest.articles.filter((article) => !isUnlistedContentPath(article.id)).length).map((seg) =>
                seg.kind === "link"
                  ? <a key={`link-${seg.label}`} href={seg.url} target="_blank" rel="noopener noreferrer" style={{ color: "var(--accent)", textDecoration: "none" }}>{seg.label}</a>
                  : <span key={`text-${seg.value}`}>{seg.value}</span>
              )}
            </div>
          </footer>
        </div>
      </div>
    </div>
  );
};

