const ArticlePage = ({
  article,
  markdown,
  isDark,
}: Readonly<{
  article: ContentArticle;
  markdown: string;
  isDark: boolean;
}>): JSX.Element => {
  const { libsReady, renderedHtml, metadata, previewRef } = useRenderedMarkdown(markdown, isDark);
  const isMobile = useIsMobile();
  const theme: Theme = isDark ? THEME_DARK : THEME_LIGHT;
  const cssVars = themeToCssVars(theme);

  useEffect(() => {
    const previousTitle = document.title;
    const title = typeof metadata?.title === "string" && metadata.title.trim().length > 0 ? metadata.title : article.title;
    document.title = title;

    const upsertMeta = (selector: string, attrs: Readonly<Record<string, string>>, content: string): (() => void) => {
      const existing = document.head.querySelector<HTMLMetaElement>(selector);
      const created = !existing;
      const tag = existing ?? document.createElement("meta");
      const previousContent = tag.getAttribute("content");

      Object.entries(attrs).forEach(([key, value]) => tag.setAttribute(key, value));
      tag.setAttribute("content", content);
      if (created) {
        document.head.appendChild(tag);
      }

      return () => {
        if (created) {
          tag.remove();
          return;
        }

        if (previousContent === null) {
          tag.removeAttribute("content");
        } else {
          tag.setAttribute("content", previousContent);
        }
      };
    };

    const cleanups: Array<() => void> = [];

    const asString = (value: unknown): string => {
      return typeof value === "string" ? value.trim() : "";
    };

    const asTags = (value: unknown): readonly string[] => {
      if (Array.isArray(value)) {
        return value.map((entry) => String(entry).trim()).filter((entry) => entry.length > 0);
      }

      if (typeof value === "string") {
        return value
          .split(",")
          .map((entry) => entry.trim())
          .filter((entry) => entry.length > 0);
      }

      return [];
    };

    const description = asString(metadata?.description);
    if (description.length > 0) {
      cleanups.push(
        upsertMeta('meta[name="description"]', { name: "description" }, description),
        upsertMeta('meta[property="og:description"]', { property: "og:description" }, description),
      );
    }

    if (title.trim().length > 0) {
      cleanups.push(upsertMeta('meta[property="og:title"]', { property: "og:title" }, title));
    }

    const author = asString(metadata?.author);
    if (author.length > 0) {
      cleanups.push(upsertMeta('meta[name="author"]', { name: "author" }, author));
    }

    const keywordTags = asTags(metadata?.keywords ?? metadata?.tags);
    if (keywordTags.length > 0) {
      cleanups.push(upsertMeta('meta[name="keywords"]', { name: "keywords" }, keywordTags.join(", ")));
    }

    const ogImage = asString(metadata?.["og:image"]);
    if (ogImage.length > 0) {
      cleanups.push(upsertMeta('meta[property="og:image"]', { property: "og:image" }, ogImage));
    }

    return () => {
      document.title = previousTitle;
      cleanups.forEach((cleanup) => cleanup());
    };
  }, [article.title, metadata]);

  useEffect(() => {
    const overlays: HTMLImageElement[] = [];

    const onBeforePrint = (): void => {
      document.querySelectorAll<HTMLCanvasElement>(".web-viz canvas").forEach((canvas) => {
        try {
          const url = canvas.toDataURL("image/png");
          const img = document.createElement("img");
          img.src = url;
          img.className = "print-canvas-overlay";
          img.style.cssText = `position:absolute;top:0;left:0;width:${canvas.offsetWidth}px;height:${canvas.offsetHeight}px;z-index:10;`;
          const parent = canvas.parentElement;
          if (parent) {
            parent.style.position = "relative";
            parent.appendChild(img);
            overlays.push(img);
          }
        } catch { /* tainted canvas — skip */ }
      });
    };

    const onAfterPrint = (): void => {
      overlays.forEach((img) => img.remove());
      overlays.length = 0;
    };

    globalThis.addEventListener("beforeprint", onBeforePrint);
    globalThis.addEventListener("afterprint", onAfterPrint);
    return () => {
      globalThis.removeEventListener("beforeprint", onBeforePrint);
      globalThis.removeEventListener("afterprint", onAfterPrint);
      onAfterPrint();
    };
  }, []);

  return (
    <div
      style={{
        ...cssVars,
        display: "flex",
        flexDirection: "column",
        background: "var(--bg)",
        fontFamily: "'Google Sans Flex', sans-serif",
        color: "var(--text)",
      }}
    >
      {libsReady ? (
        <div style={{ padding: isMobile ? "16px 12px 40px" : "20px 32px 60px", maxWidth: 1080, margin: "0 auto", width: "100%" }}>
          <article
            ref={previewRef}
            style={{
              fontSize: "16.5px",
            }}
            dangerouslySetInnerHTML={{ __html: renderedHtml }}
          />
        </div>
      ) : (
        <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", color: "var(--text-muted)", fontSize: "0.9em", gap: 10 }}>
          <span style={{ width: 16, height: 16, border: "2px solid var(--border)", borderTopColor: "var(--accent)", borderRadius: "50%", animation: "spin 0.6s linear infinite" }} />
          {" "}
          Loading libraries…
        </div>
      )}
    </div>
  );
};

const ComposePage = ({
  manifest,
  selectedArticleId,
  selectedMarkdown,
  onSelectArticle,
  onNavigateArticle,
  isDark,
}: Readonly<{
  manifest: ContentManifest;
  selectedArticleId: string;
  selectedMarkdown: string;
  onSelectArticle: (id: string) => void;
  onNavigateArticle: (id: string) => void;
  isDark: boolean;
}>): JSX.Element => {
  const draftKey = `${COMPOSE_DRAFT_PREFIX}${selectedArticleId}`;
  const isMobile = useIsMobile();
  const [markdown, setMarkdown] = useState<string>(() => {
    const draft = localStorage.getItem(draftKey);
    return draft ?? selectedMarkdown;
  });
  const [view, setView] = useState<ViewMode>(() => isMobile ? "preview" : "split");
  const [showMeta, setShowMeta] = useState<boolean>(false);
  const [syncScroll, setSyncScroll] = useState<boolean>(true);
  const [splitRatio, setSplitRatio] = useState<number>(50);
  const splitContainerRef = useRef<HTMLDivElement | null>(null);
  const draggingRef = useRef<boolean>(false);
  const monacoRef = useRef<Parameters<OnMount>[0] | null>(null);
  const previewContainerRef = useRef<HTMLDivElement | null>(null);
  const activePaneRef = useRef<"editor" | "preview" | null>(null);
  const editorRafRef = useRef<number>(0);
  const previewRafRef = useRef<number>(0);

  const { libsReady, renderedHtml, metadata, previewRef } = useRenderedMarkdown(markdown, isDark);

  const theme: Theme = isDark ? THEME_DARK : THEME_LIGHT;
  const cssVars = themeToCssVars(theme);
  const lineCount = markdown.split("\n").length;

  const syncScrollRef = useRef(syncScroll);
  syncScrollRef.current = syncScroll;
  const viewRef = useRef(view);
  viewRef.current = view;

  const frontmatterLineCount = useMemo((): number => {
    if (!markdown.startsWith("---")) return 0;
    const end = markdown.indexOf("\n---", 3);
    if (end === -1) return 0;
    return markdown.slice(0, end + 4).split("\n").length;
  }, [markdown]);
  const fmRef = useRef(frontmatterLineCount);
  fmRef.current = frontmatterLineCount;

  const onDividerPointerDown = useCallback((e: React.PointerEvent) => {
    e.preventDefault();
    draggingRef.current = true;
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  }, []);

  const onDividerPointerMove = useCallback((e: React.PointerEvent) => {
    if (!draggingRef.current || !splitContainerRef.current) return;
    const rect = splitContainerRef.current.getBoundingClientRect();
    const MIN_RATIO = 20;
    const MAX_RATIO = 80;
    const ratio = ((e.clientX - rect.left) / rect.width) * 100;
    setSplitRatio(Math.min(MAX_RATIO, Math.max(MIN_RATIO, ratio)));
  }, []);

  const onDividerPointerUp = useCallback(() => {
    draggingRef.current = false;
  }, []);

  const handleEditorMount: OnMount = useCallback((editor) => {
    monacoRef.current = editor;
    editor.onDidScrollChange(() => {
      cancelAnimationFrame(editorRafRef.current);
      editorRafRef.current = requestAnimationFrame(() => {
        if (!syncScrollRef.current || viewRef.current !== "split" || activePaneRef.current !== "editor") return;
        const container = previewContainerRef.current;
        if (!container) return;
        const ranges = editor.getVisibleRanges();
        const firstRange = ranges[0];
        if (!firstRange) return;
        const bodyLine = firstRange.startLineNumber - fmRef.current;
        if (bodyLine < 1) { container.scrollTop = 0; return; }
        const markers = container.querySelectorAll<HTMLElement>("[data-source-line]");
        let target: HTMLElement | null = null;
        for (const m of markers) {
          if (Number.parseInt(m.dataset.sourceLine ?? "0", 10) <= bodyLine) target = m;
          else break;
        }
        if (target) {
          container.scrollTop += target.getBoundingClientRect().top - container.getBoundingClientRect().top;
        }
      });
    });
  }, []);

  const handlePreviewScroll = useCallback((): void => {
    cancelAnimationFrame(previewRafRef.current);
    previewRafRef.current = requestAnimationFrame(() => {
      if (!syncScrollRef.current || viewRef.current !== "split" || activePaneRef.current !== "preview") return;
      const editor = monacoRef.current;
      const container = previewContainerRef.current;
      if (!editor || !container) return;
      const containerTop = container.getBoundingClientRect().top;
      const markers = container.querySelectorAll<HTMLElement>("[data-source-line]");
      let best: HTMLElement | null = null;
      let bestDist = Infinity;
      for (const m of markers) {
        const d = Math.abs(m.getBoundingClientRect().top - containerTop);
        if (d < bestDist) { bestDist = d; best = m; }
      }
      if (best) {
        const bodyLine = Number.parseInt(best.dataset.sourceLine ?? "1", 10);
        editor.revealLineInCenterIfOutsideViewport(bodyLine + fmRef.current);
      }
    });
  }, []);

  useEffect(() => {
    const draft = localStorage.getItem(`${COMPOSE_DRAFT_PREFIX}${selectedArticleId}`);
    const next = draft ?? selectedMarkdown;
    setMarkdown(next);
    localStorage.setItem(COMPOSE_WEB_STORAGE_KEY, next);
  }, [selectedArticleId]);

  useEffect(() => {
    const editor = monacoRef.current;
    if (!editor) return;
    const model = editor.getModel();
    if (model && model.getValue() !== markdown) {
      editor.setValue(markdown);
    }
  }, [selectedArticleId]);

  const updateMarkdown = useCallback((value = "") => {
    setMarkdown(value);
    localStorage.setItem(COMPOSE_WEB_STORAGE_KEY, value);
    localStorage.setItem(draftKey, value);
  }, [draftKey]);

  const handleResetMarkdown = useCallback(() => {
    setMarkdown(selectedMarkdown);
    localStorage.removeItem(draftKey);
    localStorage.setItem(COMPOSE_WEB_STORAGE_KEY, selectedMarkdown);
    const editor = monacoRef.current;
    if (editor) editor.setValue(selectedMarkdown);
  }, [selectedMarkdown, draftKey]);

  const handleExportMarkdown = useCallback(() => {
    const blob = new Blob([markdown], { type: "text/markdown" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `${(typeof metadata?.title === "string" ? metadata.title : "page").toLowerCase().replaceAll(/[^\w]+/g, "-")}.md`;
    link.click();
    URL.revokeObjectURL(url);
  }, [markdown, metadata]);

  const showEditor = view === "editor" || view === "split";
  const showPreview = view === "preview" || view === "split";

  return (
    <div
      style={{
        ...cssVars,
        position: "absolute",
        inset: 0,
        display: "flex",
        flexDirection: "column",
        background: "var(--bg)",
        fontFamily: "'Google Sans Flex', sans-serif",
        color: "var(--text)",
        overflow: "hidden",
      }}
    >
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          padding: "10px 16px",
          borderBottom: "1px solid var(--border)",
          background: "var(--header-bg)",
          flexShrink: 0,
          gap: 8,
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap", minWidth: 0 }}>
          <span style={{ fontWeight: 700, fontSize: "0.92em", letterSpacing: "-0.02em", whiteSpace: "nowrap" }}>Composer</span>
          <span
            style={{
              fontSize: "0.7em",
              color: "var(--text-muted)",
              background: "var(--code-bg)",
              padding: "2px 7px",
              borderRadius: 4,
              fontFamily: "'JetBrains Mono', monospace",
            }}
          >
            {lineCount}
          </span>
          {libsReady && LIB_BADGES.map((lib) => (
            <span
              key={lib}
              style={{
                fontSize: "0.6em",
                color: "var(--accent)",
                background: "var(--accent-soft)",
                padding: "1px 6px",
                borderRadius: 3,
                fontWeight: 600,
                fontFamily: "'JetBrains Mono', monospace",
                whiteSpace: "nowrap",
              }}
            >
              {lib}
            </span>
          ))}

          {metadata && (
            <button
              type="button"
              onClick={() => setShowMeta((value) => !value)}
              style={{
                fontSize: "0.65em",
                color: showMeta ? "var(--accent)" : "var(--text-muted)",
                background: showMeta ? "var(--accent-soft)" : "var(--code-bg)",
                padding: "2px 7px",
                borderRadius: 3,
                fontWeight: 600,
                border: "none",
                cursor: "pointer",
                fontFamily: "inherit",
              }}
            >
              ✦ meta
            </button>
          )}
        </div>

        <div style={{ display: "flex", alignItems: "center", gap: 3, flexShrink: 0 }}>
          <button
            type="button"
            onClick={() => onNavigateArticle(selectedArticleId)}
            title="Open article page"
            style={{
              width: 32,
              height: 32,
              borderRadius: 5,
              border: "1px solid var(--border)",
              background: "var(--editor-bg)",
              cursor: "pointer",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              color: "var(--text-muted)",
              fontSize: "0.85em",
            }}
          >
            <svg width="14" height="14" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M6 3H3v10h10v-3" />
              <path d="M9 2h5v5" />
              <path d="M14 2L7 9" />
            </svg>
          </button>
          <div style={{ display: "flex", background: "var(--code-bg)", borderRadius: 5, padding: 2, gap: 1 }}>
            {[
              { key: "editor", label: "Edit" },
              ...(isMobile ? [] : [{ key: "split", label: "Split" }]),
              { key: "preview", label: "View" },
            ].map((mode) => (
              <button
                type="button"
                key={mode.key}
                onClick={() => setView(mode.key as ViewMode)}
                style={{
                  padding: "4px 10px",
                  fontSize: "0.75em",
                  fontWeight: view === mode.key ? 600 : 400,
                  border: "none",
                  borderRadius: 3,
                  cursor: "pointer",
                  background: view === mode.key ? "var(--preview-bg)" : "transparent",
                  color: view === mode.key ? "var(--text)" : "var(--text-muted)",
                  boxShadow: view === mode.key ? "0 1px 2px rgba(0,0,0,0.08)" : "none",
                  fontFamily: "inherit",
                }}
              >
                {mode.label}
              </button>
            ))}
          </div>
          {view === "split" && (
            <button
              type="button"
              onClick={() => setSyncScroll((v) => !v)}
              title={syncScroll ? "Disable sync scroll" : "Enable sync scroll"}
              style={{
                width: 32,
                height: 32,
                borderRadius: 5,
                border: "1px solid var(--border)",
                background: syncScroll ? "var(--accent-soft)" : "var(--editor-bg)",
                cursor: "pointer",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                color: syncScroll ? "var(--accent)" : "var(--text-muted)",
                fontSize: "0.85em",
              }}
            >
              <svg width="14" height="14" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M4 1v14M12 1v14" />
                <path d="M4 5l3-2 3 2" />
                <path d="M4 11l3 2 3-2" />
              </svg>
            </button>
          )}
          <button
            type="button"
            onClick={handleResetMarkdown}
            title="Discard edits and restore original content"
            style={{
              padding: "5px 12px",
              fontSize: "0.75em",
              fontWeight: 600,
              border: "1px solid var(--border)",
              borderRadius: 5,
              cursor: "pointer",
              background: "var(--editor-bg)",
              color: "var(--text-muted)",
              fontFamily: "inherit",
            }}
          >
            Reset
          </button>
          <button
            type="button"
            onClick={handleExportMarkdown}
            style={{
              padding: "5px 12px",
              fontSize: "0.75em",
              fontWeight: 600,
              border: "none",
              borderRadius: 5,
              cursor: "pointer",
              background: "var(--accent)",
              color: "white",
              fontFamily: "inherit",
            }}
          >
            Export
          </button>
        </div>
      </div>

      {showMeta && metadata && (
        <div
          style={{
            borderBottom: "1px solid var(--border)",
            background: "var(--code-bg)",
            padding: "10px 16px",
            display: "flex",
            flexWrap: "wrap",
            gap: "6px 18px",
            fontSize: "0.78em",
            flexShrink: 0,
            animation: "fadeIn 0.15s ease",
          }}
        >
          {Object.entries(metadata).map(([key, value]) => (
            <div key={key} style={{ display: "flex", alignItems: "baseline", gap: 5 }}>
              <span style={{ color: "var(--text-muted)", fontFamily: "'JetBrains Mono', monospace", fontSize: "0.88em" }}>{key}</span>
              <span style={{ color: "var(--text)" }}>
                {Array.isArray(value)
                  ? value.map((tag, index) => (
                      <span
                        key={`${tag}-${index}`}
                        style={{
                          background: "var(--accent-soft)",
                          color: "var(--accent)",
                          padding: "1px 6px",
                          borderRadius: 3,
                          fontSize: "0.88em",
                          fontWeight: 500,
                          marginRight: 3,
                        }}
                      >
                        {tag}
                      </span>
                    ))
                  : value}
              </span>
            </div>
          ))}
        </div>
      )}

      <div ref={splitContainerRef} style={{ flex: 1, display: "flex", overflow: "hidden" }}>
        {showEditor && (
          // eslint-disable-next-line jsx-a11y/no-static-element-interactions
          <div
            onMouseEnter={() => { activePaneRef.current = "editor"; }}
            style={{
              flex: view === "split" ? `0 0 ${splitRatio}%` : 1,
              display: "flex",
              flexDirection: "column",
              background: "var(--editor-bg)",
              overflow: "hidden",
            }}
          >
            <Editor
              language="markdown"
              theme={isDark ? "vs-dark" : "vs"}
              value={markdown}
              onChange={updateMarkdown}
              onMount={handleEditorMount}
              options={{
                fontSize: 14,
                fontFamily: "'JetBrains Mono', 'Fira Code', monospace",
                lineHeight: 24,
                minimap: { enabled: false },
                wordWrap: "on",
                lineNumbers: "on",
                renderWhitespace: "none",
                scrollBeyondLastLine: false,
                padding: { top: 14 },
                tabSize: 2,
                automaticLayout: true,
                overviewRulerLanes: 0,
                hideCursorInOverviewRuler: true,
                scrollbar: { verticalScrollbarSize: 8, horizontalScrollbarSize: 8 },
                bracketPairColorization: { enabled: true },
              }}
            />
          </div>
        )}

        {view === "split" && (
          // eslint-disable-next-line jsx-a11y/no-static-element-interactions
          <div
            onPointerDown={onDividerPointerDown}
            onPointerMove={onDividerPointerMove}
            onPointerUp={onDividerPointerUp}
            style={{
              width: 6,
              cursor: "col-resize",
              background: draggingRef.current ? "var(--accent)" : "var(--border)",
              flexShrink: 0,
              transition: "background 0.15s",
            }}
            onMouseEnter={(e) => { (e.currentTarget as HTMLElement).style.background = "var(--accent)"; }}
            onMouseLeave={(e) => { if (!draggingRef.current) (e.currentTarget as HTMLElement).style.background = "var(--border)"; }}
          />
        )}

        {showPreview && (
          // eslint-disable-next-line jsx-a11y/no-static-element-interactions
          <div
            ref={previewContainerRef}
            onScroll={handlePreviewScroll}
            onMouseEnter={() => { activePaneRef.current = "preview"; }}
            style={{
              ...cssVars,
              flex: 1,
              display: "flex",
              flexDirection: "column",
              background: "var(--bg)",
              fontFamily: "'Google Sans Flex', sans-serif",
              color: "var(--text)",
              overflowY: "auto",
            }}
          >
            {libsReady ? (
              <div style={{ padding: isMobile ? "16px 12px 40px" : "20px 32px 60px", maxWidth: 1080, margin: "0 auto", width: "100%" }}>
                <article
                  ref={previewRef}
                  style={{ fontSize: "16.5px" }}
                  dangerouslySetInnerHTML={{ __html: renderedHtml }}
                />
              </div>
            ) : (
              <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", color: "var(--text-muted)", fontSize: "0.9em", gap: 10 }}>
                <span style={{ width: 16, height: 16, border: "2px solid var(--border)", borderTopColor: "var(--accent)", borderRadius: "50%", animation: "spin 0.6s linear infinite" }} />
                {" "}
                Loading libraries…
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

const resolveArticlePage = (props: Readonly<{
  route: Readonly<{ kind: "article"; articleId: string }>;
  manifest: ContentManifest;
  articleMarkdowns: Readonly<Record<string, string>>;
  markdownLoadingIds: Readonly<Record<string, boolean>>;
  markdownErrorIds: Readonly<Record<string, string>>;
  retryArticle: (id: string) => void;
  openHome: () => void;
  isDark: boolean;
}>): JSX.Element => {
  const { route, manifest, articleMarkdowns, markdownLoadingIds, markdownErrorIds, retryArticle, openHome, isDark } = props;
  const article = findArticleById(manifest, route.articleId);
  if (!article) {
    return <NotFoundPage isDark={isDark} onGoHome={openHome} />;
  }
  const errorMsg = markdownErrorIds[route.articleId];
  if (errorMsg) {
    return <ErrorPage isDark={isDark} title="Failed to load article" message={errorMsg} onRetry={() => retryArticle(route.articleId)} onGoHome={openHome} />;
  }
  const markdown = articleMarkdowns[route.articleId];
  if (markdown === undefined || Boolean(markdownLoadingIds[route.articleId])) {
    return <RouteLoader isDark={isDark} label="Loading article…" />;
  }
  return <ArticlePage article={article} markdown={markdown} isDark={isDark} />;
};

const resolveCurrentPage = ({
  route,
  manifest,
  composeArticleId,
  selectedComposeMarkdown,
  articleMarkdowns,
  markdownLoadingIds,
  markdownErrorIds,
  selectComposeArticle,
  openArticle,
  openHome,
  retryArticle,
  isDark,
}: Readonly<{
  route: AppRoute;
  manifest: ContentManifest;
  composeArticleId: string;
  selectedComposeMarkdown: string;
  articleMarkdowns: Readonly<Record<string, string>>;
  markdownLoadingIds: Readonly<Record<string, boolean>>;
  markdownErrorIds: Readonly<Record<string, string>>;
  selectComposeArticle: (id: string) => void;
  openArticle: (id: string) => void;
  openHome: () => void;
  retryArticle: (id: string) => void;
  isDark: boolean;
}>): JSX.Element => {
  if (route.kind === "compose") {
    if (composeArticleId) {
      const isComposeLoading = Boolean(markdownLoadingIds[composeArticleId]) && articleMarkdowns[composeArticleId] === undefined;
      if (isComposeLoading && selectedComposeMarkdown.length === 0) {
        return <RouteLoader isDark={isDark} label="Loading compose content…" />;
      }

      return (
        <ComposePage
          manifest={manifest}
          selectedArticleId={composeArticleId}
          selectedMarkdown={selectedComposeMarkdown}
          onSelectArticle={selectComposeArticle}
          onNavigateArticle={openArticle}
          isDark={isDark}
        />
      );
    }

    return <RouteLoader isDark={isDark} label="Loading compose…" />;
  }

  if (route.kind === "article") {
    return resolveArticlePage({ route, manifest, articleMarkdowns, markdownLoadingIds, markdownErrorIds, retryArticle, openHome, isDark });
  }

  if (route.kind === "not-found") {
    return <NotFoundPage isDark={isDark} onGoHome={openHome} />;
  }

  return <HomePage manifest={manifest} onOpenArticle={openArticle} isDark={isDark} />;
};

export default function App(): JSX.Element {
  const [manifest, setManifest] = useState<ContentManifest | null>(null);
  const [manifestError, setManifestError] = useState<string | null>(null);
  const [articleMarkdowns, setArticleMarkdowns] = useState<Record<string, string>>({});
  const [markdownLoadingIds, setMarkdownLoadingIds] = useState<Record<string, boolean>>({});
  const [markdownErrorIds, setMarkdownErrorIds] = useState<Record<string, string>>({});
  const articleMarkdownsRef = useRef<Record<string, string>>({});
  const markdownInFlightRef = useRef<Record<string, Promise<string>>>({});
  const [pathname, setPathname] = useState<string>(globalThis.location.pathname);

  useEffect(() => {
    fetchContentManifest()
      .then((data) => {
        setManifest(data);
      })
      .catch((error: unknown) => {
        const message = error instanceof Error ? error.message : String(error);
        setManifestError(message);
      });
  }, []);

  useEffect(() => {
    const onPopState = () => setPathname(globalThis.location.pathname);
    globalThis.addEventListener("popstate", onPopState);
    return () => globalThis.removeEventListener("popstate", onPopState);
  }, []);

  const navigate = useCallback((nextPath: string, replace?: boolean) => {
    if (replace) {
      globalThis.history.replaceState({}, "", nextPath);
    } else {
      globalThis.history.pushState({}, "", nextPath);
    }
    setPathname(globalThis.location.pathname);
  }, []);

  const route = useMemo(() => {
    if (!manifest) {
      return { kind: "home" } as AppRoute;
    }
    return resolveRoute(pathname, manifest);
  }, [pathname, manifest]);

  const openCompose = useCallback(() => {
    if (manifest && route.kind === "article") {
      const article = findArticleById(manifest, route.articleId);
      if (article) {
        const articleRelativePath = normalizePath(stripSitePrefix(article.route));
        navigate(`/reads/compose${articleRelativePath}`);
        return;
      }
    }

    navigate("/reads/compose");
  }, [navigate, manifest, route]);

  const openHome = useCallback(() => {
    navigate("/reads/");
  }, [navigate]);

  const openArticle = useCallback((articleId: string) => {
    if (!manifest) {
      return;
    }

    const article = findArticleById(manifest, articleId);
    if (!article) {
      return;
    }
    navigate(toReadPath(article.route));
  }, [navigate, manifest]);

  const openPath = useCallback((path: string) => {
    navigate(path);
  }, [navigate]);

  const [composeArticleId, setComposeArticleId] = useState<string>("");
  const [themeMode, setThemeMode] = useState<ThemeMode>(readStoredTheme);
  const [isDark, setIsDark] = useState<boolean>(() => resolveIsDark(readStoredTheme()));

  const handleSetThemeMode = useCallback((mode: ThemeMode | "default") => {
    if (mode === "default") {
      localStorage.removeItem(THEME_STORAGE_KEY);
      const resolved = SITE_CONFIG.defaultTheme;
      setThemeMode(resolved);
      setIsDark(resolveIsDark(resolved));
      return;
    }
    setThemeMode(mode);
    localStorage.setItem(THEME_STORAGE_KEY, mode);
    setIsDark(resolveIsDark(mode));
  }, []);

  useEffect(() => {
    if (themeMode !== "system") return;
    const mq = globalThis.matchMedia("(prefers-color-scheme: dark)");
    const handler = (e: MediaQueryListEvent) => setIsDark(e.matches);
    mq.addEventListener("change", handler);
    return () => mq.removeEventListener("change", handler);
  }, [themeMode]);

  const selectComposeArticle = useCallback((articleId: string) => {
    setComposeArticleId(articleId);
    if (!manifest) {
      return;
    }

    const article = findArticleById(manifest, articleId);
    if (!article) {
      return;
    }

    const articleRelativePath = normalizePath(stripSitePrefix(article.route));
    navigate(`/reads/compose${articleRelativePath}`);
  }, [manifest, navigate]);

  useEffect(() => {
    if (!manifest || route.kind !== "compose") {
      return;
    }

    if (route.articleId && route.articleId !== composeArticleId) {
      setComposeArticleId(route.articleId);
      return;
    }

    if (!route.articleId && !composeArticleId) {
      setComposeArticleId(findInitialArticleId(manifest));
    }
  }, [manifest, composeArticleId, route.kind, route]);

  useEffect(() => {
    articleMarkdownsRef.current = articleMarkdowns;
  }, [articleMarkdowns]);

  const ensureMarkdownLoaded = useCallback(
    async (articleId: string): Promise<string> => {
      const existing = articleMarkdownsRef.current[articleId];
      if (existing !== undefined) {
        return existing;
      }

      const inFlight = markdownInFlightRef.current[articleId];
      if (inFlight) {
        return inFlight;
      }

      setMarkdownLoadingIds((previous) => ({ ...previous, [articleId]: true }));
      setMarkdownErrorIds((previous) => {
        if (!previous[articleId]) return previous;
        const next = { ...previous };
        delete next[articleId];
        return next;
      });

      const request = fetchMarkdownContent(articleId)
        .then((markdown) => {
          setArticleMarkdowns((previous) => {
            if (previous[articleId] !== undefined) {
              return previous;
            }
            return { ...previous, [articleId]: markdown };
          });
          return markdown;
        })
        .catch((error: unknown) => {
          const message = error instanceof Error ? error.message : String(error);
          setMarkdownErrorIds((previous) => ({ ...previous, [articleId]: message }));
          throw error;
        })
        .finally(() => {
          delete markdownInFlightRef.current[articleId];
          setMarkdownLoadingIds((previous) => ({ ...previous, [articleId]: false }));
        });

      markdownInFlightRef.current[articleId] = request;
      return request;
    },
    [],
  );

  const retryArticle = useCallback((articleId: string) => {
    setMarkdownErrorIds((previous) => {
      const next = { ...previous };
      delete next[articleId];
      return next;
    });
    delete markdownInFlightRef.current[articleId];
    setArticleMarkdowns((previous) => {
      const next = { ...previous };
      delete next[articleId];
      return next;
    });
    articleMarkdownsRef.current = { ...articleMarkdownsRef.current };
    delete articleMarkdownsRef.current[articleId];
    void ensureMarkdownLoaded(articleId).catch(() => {});
  }, [ensureMarkdownLoaded]);

  useEffect(() => {
    if (route.kind !== "article") {
      return;
    }

    void ensureMarkdownLoaded(route.articleId).catch(() => {
      // error tracked via markdownErrorIds
    });
  }, [route, ensureMarkdownLoaded]);

  useEffect(() => {
    if (route.kind !== "compose" || !composeArticleId) {
      return;
    }

    void ensureMarkdownLoaded(composeArticleId).catch(() => {
      // error tracked via markdownErrorIds
    });
  }, [route.kind, composeArticleId, ensureMarkdownLoaded]);

  if (manifestError) {
    return <ErrorPage isDark={isDark} title="Failed to load content" message={manifestError} onRetry={() => globalThis.location.reload()} onGoHome={() => { globalThis.location.href = "/reads/"; }} />;
  }

  if (!manifest) {
    return <RouteLoader isDark={isDark} label="Loading content…" />;
  }

  const selectedComposeMarkdown =
    articleMarkdowns[composeArticleId] ??
    localStorage.getItem(COMPOSE_WEB_STORAGE_KEY) ??
    "";

  const page = resolveCurrentPage({
    route,
    manifest,
    composeArticleId,
    selectedComposeMarkdown,
    articleMarkdowns,
    markdownLoadingIds,
    markdownErrorIds,
    selectComposeArticle,
    openArticle,
    openHome,
    retryArticle,
    isDark,
  });

  return (
    <ErrorBoundary isDark={isDark} onGoHome={openHome}>
      <SharedShell
        manifest={manifest}
        currentPath={pathname}
        onNavigateHome={openHome}
        onNavigateCompose={openCompose}
        onNavigateTo={openPath}
        onNavigateArticle={openArticle}
        sidebarArticleOverride={route.kind === "compose" ? selectComposeArticle : undefined}
        themeMode={themeMode}
        onSetThemeMode={handleSetThemeMode}
        isDark={isDark}
      >
        {page}
      </SharedShell>
    </ErrorBoundary>
  );
}
