export const preProcessColumns = (md: string): string => {
  return md.replaceAll(/^:::columns-(\d+)\s*\n([\s\S]*?)^:::\s*$/gm, (_m, _n: string, content: string) => {
    const cols = content.split(/^\+\+\+\s*$/m);
    const divs = cols
      .map((column) => `<div class="md-col" style="flex:1;min-width:180px;">\n\n${column.trim()}\n\n</div>`)
      .join("\n");

    return `<div class="md-columns" style="display:flex;flex-wrap:wrap;gap:24px;">\n${divs}\n</div>\n`;
  });
};
