const SECTION_RE = /^:::section(?:\s+\{([^}]*)\})?\s*\n([\s\S]*?)^:::\s*$/gm;

type SectionChrome = Readonly<Record<string, string>>;

const parseChrome = (raw: string): SectionChrome => {
  const chrome: Record<string, string> = {};
  for (const token of raw.split(/\s+/)) {
    const kv = /^(\w[\w-]*)[:=](.+)$/.exec(token);
    if (kv?.[1] && kv[2]) chrome[kv[1]] = kv[2];
    else if (token) chrome[token] = "true";
  }
  return chrome;
};

const buildSectionHtml = (content: string, chrome: SectionChrome): string => {
  const hasBorder = chrome.border === "true";
  const hasBg = chrome.bg === "true";
  const title = chrome.title?.replaceAll("-", " ") ?? "";
  const padding = chrome.padding ?? "20px";
  const radius = chrome.radius ?? "10px";

  const styles: string[] = [`margin:16px 0`, `padding:${padding}`, `border-radius:${radius}`];
  if (hasBorder) styles.push("border:1px solid var(--border)");
  if (hasBg) styles.push("background:var(--code-bg)");

  const borderRule = hasBorder ? "padding-bottom:8px;border-bottom:1px solid var(--border);" : "";
  const titleBar = title
    ? `<div style="font-family:'JetBrains Mono',monospace;font-size:0.7em;text-transform:uppercase;letter-spacing:0.08em;color:var(--accent);font-weight:600;margin-bottom:12px;${borderRule}">${title}</div>`
    : "";

  return `<div class="md-section" style="${styles.join(";")}">\n${titleBar}\n\n${content.trim()}\n\n</div>\n`;
};

export const preProcessSections = (md: string): string => {
  return md.replaceAll(SECTION_RE, (_m, flags: string | undefined, content: string) => {
    const chrome = flags ? parseChrome(flags) : {};
    return buildSectionHtml(content, chrome);
  });
};
